// 1: Accept a string input
// 2: Use a Dictionary<char, int> to count characters
// 3: Ignore spaces while counting
// 4: Return the character counts

hints.code:
foreach (char c in input)
{
    if (c != ' ')
    {
        if (charCount.ContainsKey(c))
        {
            charCount[c]++;
        }
        else
        {
            charCount[c] = 1;
        }
    }
}
